def reverse_words_preserving_spaces(s: str) -> str:
    if not s:
        return ""

    words = []
    current_word = []
    for char in s:
        if char == ' ':
            if current_word:
                words.append("".join(current_word))
                current_word = []
        else:
            current_word.append(char)
    if current_word:
        words.append("".join(current_word))

    reversed_words = words[::-1]
    result = []
    word_index = 0

    for char in s:
        if char == ' ':
            result.append(' ')
        else:
            if word_index < len(reversed_words):
                result.extend(list(reversed_words[word_index]))
                word_index += 1
    return "".join(result)

def run_length_encoding(s: str) -> str:
    if not s:
        return ""

    encoded_string = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i - 1]:
            count += 1
        else:
            encoded_string.append(str(count))
            encoded_string.append(s[i - 1])
            count = 1
    encoded_string.append(str(count))
    encoded_string.append(s[-1])
    return "".join(encoded_string)

def is_match(s: str, p: str) -> bool:
    memo = {}

    def dp(i, j):
        if (i, j) in memo:
            return memo[(i, j)]

        if j == len(p):
            return i == len(s)

        first_match = (i < len(s)) and (p[j] == s[i] or p[j] == '.')

        if j + 1 < len(p) and p[j + 1] == '*':
            # Case 1: '*' matches zero occurrences of the preceding element
            # Case 2: '*' matches one or more occurrences of the preceding element
            ans = dp(i, j + 2) or (first_match and dp(i + 1, j))
        else:
            ans = first_match and dp(i + 1, j + 1)

        memo[(i, j)] = ans
        return ans

    return dp(0, 0)

import itertools

def string_permutations_unique(s: str) -> list[str]:
    return list(set("".join(p) for p in itertools.permutations(s)))

def roman_to_int(s: str) -> int:
    roman_map = {
        'I': 1, 'V': 5, '        X': 10, 'L': 50,
        'C': 100, 'D': 500, 'M': 1000
    }

    total = 0
    i = 0
    while i < len(s):
        if i + 1 < len(s) and roman_map[s[i]] < roman_map[s[i+1]]:
            total += roman_map[s[i+1]] - roman_map[s[i]]
            i += 2
        else:
            total += roman_map[s[i]]
            i += 1

    return total

def int_to_roman(num: int) -> str:
    roman_map = {
        1000: 'M', 900: 'CM', 500: 'D', 400: 'CD',
        100: 'C', 90: 'XC', 50: 'L', 40: 'XL',
        10: 'X', 9: 'IX', 5: 'V', 4: 'IV', 1: 'I'
    }

    result = []
    for value, numeral in roman_map.items():
        while num >= value:
            result.append(numeral)
            num -= value
    return "".join(result)

def caesar_cipher(text: str, shift: int, encode: bool) -> str:
    result = []
    if not encode:
        shift = -shift

    for char in text:
        if 'a' <= char <= 'z':
            start = ord('a')
            shifted_char = chr(((ord(char) - start + shift) % 26) + start)
            result.append(shifted_char)
        elif 'A' <= char <= 'Z':
            start = ord('A')
            shifted_char = chr(((ord(char) - start + shift) % 26) + start)
            result.append(shifted_char)
        else:
            result.append(char)
    return "".join(result)

import collections

def min_window_substring(s: str, t: str) -> str:
    if not t:
        return ""

    target_counts = collections.Counter(t)
    window_counts = collections.Counter()

    required_chars = len(target_counts)
    formed_chars = 0

    left = 0
    min_len = float('inf')
    min_window_start = 0

    for right in range(len(s)):
        char = s[right]
        window_counts[char] += 1

        if char in target_counts and window_counts[char] == target_counts[char]:
            formed_chars += 1

        while formed_chars == required_chars:
            current_window_len = right - left + 1
            if current_window_len < min_len:
                min_len = current_window_len
                min_window_start = left

            char_to_remove = s[left]
            window_counts[char_to_remove] -= 1

            if char_to_remove in target_counts and window_counts[char_to_remove] < target_counts[char_to_remove]:
                formed_chars -= 1

            left += 1

    if min_len == float('inf'):
        return ""
    else:
        return s[min_window_start : min_window_start + min_len]

from collections import defaultdict

def group_anagrams(strs: list[str]) -> list[list[str]]:
    anagram_groups = defaultdict(list)
    for s in strs:
        sorted_s = "".join(sorted(s))
        anagram_groups[sorted_s].append(s)
    return list(anagram_groups.values())

def is_balanced(s: str) -> bool:
    stack = []
    mapping = {")": "(", "}": "{", "]": "["}

    for char in s:
        if char in mapping.values():
            stack.append(char)
        elif char in mapping.keys():
            if not stack or mapping[char] != stack.pop():
                return False
        else:
            # Handle unexpected characters if necessary, though problem statement implies only these three types
            pass

    return not stack

def longest_common_prefix(strs: list[str]) -> str:
    if not strs:
        return ""

    if len(strs) == 1:
        return strs[0]

    prefix = strs[0]
    for i in range(1, len(strs)):
        while strs[i].find(prefix) != 0:
            prefix = prefix[:-1]
            if not prefix:
                return ""
    return prefix

def count_distinct_subsequences(text: str, pattern: str) -> int:
    n = len(text)
    m = len(pattern)

    dp = [[0] * (m + 1) for _ in range(n + 1)]

    for i in range(n + 1):
        dp[i][0] = 1

    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if text[i - 1] == pattern[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j]
            else:
                dp[i][j] = dp[i - 1][j]

    return dp[n][m]

def interleave_strings(s1: str, s2: str) -> str:
    result = []
    len1 = len(s1)
    len2 = len(s2)
    max_len = max(len1, len2)

    for i in range(max_len):
        if i < len1:
            result.append(s1[i])
        if i < len2:
            result.append(s2[i])

    return "".join(result)

def remove_all_adjacent_duplicates_repeatedly(s: str) -> str:
    stack = []
    for char in s:
        if stack and stack[-1] == char:
            stack.pop()
        else:
            stack.append(char)

    result = "".join(stack)

    while True:
        original_len = len(result)
        new_result_list = []
        i = 0
        while i < len(result):
            if i + 1 < len(result) and result[i] == result[i+1]:
                while i + 1 < len(result) and result[i] == result[i+1]:
                    i += 1
            else:
                new_result_list.append(result[i])
            i += 1

        result = "".join(new_result_list)
        if len(result) == original_len:
            break

    return result

def is_rotation(s1: str, s2: str) -> bool:
    if len(s1) != len(s2):
        return False
    if not s1 and not s2:
        return True

    temp = s1 + s1
    return s2 in temp

def first_non_repeating_character(s: str) -> str:
    char_counts = {}
    for char in s:
        char_counts[char] = char_counts.get(char, 0) + 1

    for char in s:
        if char_counts[char] == 1:
            return char
    return ""

def is_match(s: str, p: str) -> bool:
    s_len = len(s)
    p_len = len(p)

    dp = [[False] * (p_len + 1) for _ in range(s_len + 1)]

    dp[0][0] = True

    for j in range(1, p_len + 1):
        if p[j - 1] == '*':
            dp[0][j] = dp[0][j - 1]

    for i in range(1, s_len + 1):
        for j in range(1, p_len + 1):
            if p[j - 1] == '*':
                dp[i][j] = dp[i][j - 1] or dp[i - 1][j]
            elif p[j - 1] == '?' or s[i - 1] == p[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
    return dp[s_len][p_len]

def validate_ipv4_address(ip: str) -> bool:
    parts = ip.split('.')
    if len(parts) != 4:
        return False

    for part in parts:
        if not part.isdigit():
            return False

        if len(part) > 1 and part.startswith('0'):
            return False

        num = int(part)
        if not (0 <= num <= 255):
            return False

    return True

def merge(nums1: list[int], m: int, nums2: list[int], n: int) -> None:
    p1 = m - 1
    p2 = n - 1
    p = m + n - 1

    while p1 >= 0 and p2 >= 0:
        if nums1[p1] > nums2[p2]:
            nums1[p] = nums1[p1]
            p1 -= 1
        else:
            nums1[p] = nums2[p2]
            p2 -= 1
        p -= 1

    while p2 >= 0:
        nums1[p] = nums2[p2]
        p2 -= 1
        p -= 1

import heapq

def find_kth_largest(nums: list[int], k: int) -> int:
    return heapq.nlargest(k, nums)[-1]

def quicksort(arr: list[int]) -> list[int]:
    if len(arr) <= 1:
        return arr

    pivot = arr[len(arr) // 2]
    left = [x for x in arr if x < pivot]
    middle = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]

    return quicksort(left) + middle + quicksort(right)

def maximum_subarray_sum(nums: list[int]) -> int:
    if not nums:
        return 0

    max_so_far = nums[0]
    current_max = nums[0]

    for i in range(1, len(nums)):
        current_max = max(nums[i], current_max + nums[i])
        max_so_far = max(max_so_far, current_max)

    return max_so_far
